import{c as a,Q as o,j as d,m as i}from"./chunks/framework.BkjtU8k0.js";const f=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1779097958000}'),l={name:"guide/faq.md"};function c(r,e,t,s,h,p){return o(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="url-预览为什么失败或空白" tabindex="-1">URL 预览为什么失败或空白 <a class="header-anchor" href="#url-预览为什么失败或空白" aria-label="Permalink to &quot;URL 预览为什么失败或空白&quot;">​</a></h2><p>组件在浏览器里通过 <code>axios</code> 请求目标文件，所以最常见的失败原因是:</p><ul><li>文件地址本身不可访问</li><li>服务端没有正确配置 CORS</li><li>鉴权信息只能在宿主系统内使用，浏览器直接请求拿不到文件</li></ul><p>如果你的场景带有登录态、签名 URL 或内部权限体系，优先使用 <code>file</code> 参数或 <a href="/guide/iframe">Iframe 嵌入</a>。</p><h2 id="为什么带查询参数的下载地址有时识别不到格式" tabindex="-1">为什么带查询参数的下载地址有时识别不到格式 <a class="header-anchor" href="#为什么带查询参数的下载地址有时识别不到格式" aria-label="Permalink to &quot;为什么带查询参数的下载地址有时识别不到格式&quot;">​</a></h2><p>当前预览器会根据文件名扩展名判断该走哪条渲染链路。如果 URL 形如 <code>/download?id=123</code>，路径里没有明确的 <code>.pdf</code>、<code>.docx</code>、<code>.xlsx</code> 这类后缀，渲染器就很难准确识别文件类型。</p><p>这类地址最稳妥的做法是:</p><ul><li>先在业务侧请求文件</li><li>拿到 <code>Blob</code> 或 <code>ArrayBuffer</code></li><li>再包装成带正确文件名的 <code>File</code></li></ul><h2 id="为什么一定要给父容器设置高度" tabindex="-1">为什么一定要给父容器设置高度 <a class="header-anchor" href="#为什么一定要给父容器设置高度" aria-label="Permalink to &quot;为什么一定要给父容器设置高度&quot;">​</a></h2><p>预览器默认使用 <code>width: 100%</code> 和 <code>height: 100%</code> 填满父容器。如果父容器没有稳定高度，渲染区域就会塌陷，看起来像“没有内容”。</p><h2 id="file-和-url-同时传时-谁优先" tabindex="-1"><code>file</code> 和 <code>url</code> 同时传时，谁优先 <a class="header-anchor" href="#file-和-url-同时传时-谁优先" aria-label="Permalink to &quot;`file` 和 `url` 同时传时，谁优先&quot;">​</a></h2><p>当前行为是 <code>file</code> 优先。如果后续把 <code>file</code> 清空，而 <code>url</code> 仍然存在，组件会回退到 <code>url</code> 再次加载。</p><h2 id="doc-和-docx-的渲染实现一样吗" tabindex="-1"><code>.doc</code> 和 <code>.docx</code> 的渲染实现一样吗 <a class="header-anchor" href="#doc-和-docx-的渲染实现一样吗" aria-label="Permalink to &quot;`.doc` 和 `.docx` 的渲染实现一样吗&quot;">​</a></h2><p>不一样。</p><ul><li><code>docx</code> 使用 <code>docx-preview</code></li><li><code>doc</code> 使用 <code>msdoc-viewer</code></li></ul><p>另外，<code>.doc</code> 还额外套了一层 Word 风格页面容器，让页面在灰色背景中居中展示。</p><h2 id="blob-或-arraybuffer-能直接传给-file-吗" tabindex="-1"><code>Blob</code> 或 <code>ArrayBuffer</code> 能直接传给 <code>file</code> 吗 <a class="header-anchor" href="#blob-或-arraybuffer-能直接传给-file-吗" aria-label="Permalink to &quot;`Blob` 或 `ArrayBuffer` 能直接传给 `file` 吗&quot;">​</a></h2><p>从接入经验上看，不建议直接把裸 <code>Blob</code> 或 <code>ArrayBuffer</code> 塞进去。</p><p>原因很简单: 预览器要靠文件名扩展名来选择渲染器，而裸二进制本身通常不带可靠的文件名。更稳妥的方式是:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> File</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([blobOrBuffer], </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;report.xlsx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这样既保留了二进制链路，也把渲染器最依赖的扩展名补齐了。</p><h2 id="xls-和-xlsx-的样式能力有什么差异" tabindex="-1"><code>xls</code> 和 <code>xlsx</code> 的样式能力有什么差异 <a class="header-anchor" href="#xls-和-xlsx-的样式能力有什么差异" aria-label="Permalink to &quot;`xls` 和 `xlsx` 的样式能力有什么差异&quot;">​</a></h2><p>当前表格预览统一走 <code>styled-exceljs</code>，会读取文件里能表达的列宽、行高、合并单元格、边框、填充和对齐等信息。差异主要来自格式本身: <code>xlsx</code> 通常保存的样式信息更完整，而 <code>xls/csv/ods</code> 等格式可能缺少部分现代样式描述。</p><h2 id="html-文件为什么是按文本显示的" tabindex="-1"><code>html</code> 文件为什么是按文本显示的 <a class="header-anchor" href="#html-文件为什么是按文本显示的" aria-label="Permalink to &quot;`html` 文件为什么是按文本显示的&quot;">​</a></h2><p>因为当前版本把 <code>html</code> 放在代码/文本类型里处理，它会展示并高亮源内容，而不会把文件当作网页直接执行。这是为了保证预览行为更安全、更可控，也更适合代码和模板查看。</p><h2 id="为什么-dwg-会提示转换为-dxf" tabindex="-1">为什么 DWG 会提示转换为 DXF <a class="header-anchor" href="#为什么-dwg-会提示转换为-dxf" aria-label="Permalink to &quot;为什么 DWG 会提示转换为 DXF&quot;">​</a></h2><p>DXF 当前走 <code>@cadview/core</code> 在浏览器端直接预览。DWG 是专有二进制格式，常见前端解析包存在 GPL 授权约束或需要额外转换运行时，所以组件不会默认把 DWG 解析器打进包里。业务侧可以先把 DWG 转成 DXF，再交给预览器展示。</p><h2 id="代码文件会执行吗" tabindex="-1">代码文件会执行吗 <a class="header-anchor" href="#代码文件会执行吗" aria-label="Permalink to &quot;代码文件会执行吗&quot;">​</a></h2><p>不会。代码/文本链路使用 <code>highlight.js</code> 做源码高亮，只展示内容，不执行 <code>html</code>、<code>js</code> 或模板里的脚本。</p><h2 id="大小写扩展名会影响识别吗" tabindex="-1">大小写扩展名会影响识别吗 <a class="header-anchor" href="#大小写扩展名会影响识别吗" aria-label="Permalink to &quot;大小写扩展名会影响识别吗&quot;">​</a></h2><p>不会。扩展名匹配时会统一转成小写，所以 <code>PDF</code>、<code>DocX</code>、<code>SVG</code> 这类大小写差异不会影响命中。</p><h2 id="为什么-ppt-不能像-pptx-一样直接打开" tabindex="-1">为什么 <code>ppt</code> 不能像 <code>pptx</code> 一样直接打开 <a class="header-anchor" href="#为什么-ppt-不能像-pptx-一样直接打开" aria-label="Permalink to &quot;为什么 `ppt` 不能像 `pptx` 一样直接打开&quot;">​</a></h2><p>当前内置的是 <code>pptx</code> 渲染链路，老的二进制 <code>ppt</code> 并没有注册对应处理器。如果你的业务里大量存在 <code>ppt</code>，建议在接入侧先做格式转换，或者统一导出为 <code>pptx</code> / <code>pdf</code>。</p><h2 id="iframe-模式为什么要带-from" tabindex="-1">iframe 模式为什么要带 <code>from</code> <a class="header-anchor" href="#iframe-模式为什么要带-from" aria-label="Permalink to &quot;iframe 模式为什么要带 `from`&quot;">​</a></h2><p>这是为了限制消息来源。预览器接收 <code>Blob</code> 时会校验 <code>event.origin === from</code>，只有来源匹配才会渲染，这样能避免任意页面向 iframe 注入数据。</p><h2 id="大文件会不会慢" tabindex="-1">大文件会不会慢 <a class="header-anchor" href="#大文件会不会慢" aria-label="Permalink to &quot;大文件会不会慢&quot;">​</a></h2><p>会，尤其是复杂的 Office 文档和大体积 PDF。因为解析发生在浏览器里，最终体验取决于:</p><ul><li>文件体积和复杂度</li><li>当前设备的 CPU 和内存</li><li>浏览器本身的性能</li></ul><p>如果你的业务里经常处理超大文件，建议优先用真实样本做联调测试。</p><h2 id="公开仓库里为什么没有源码" tabindex="-1">公开仓库里为什么没有源码 <a class="header-anchor" href="#公开仓库里为什么没有源码" aria-label="Permalink to &quot;公开仓库里为什么没有源码&quot;">​</a></h2><p>公开 GitHub 仓库面向“成品分发”，提供的是混淆压缩后的组件库、可部署 Demo、文档静态产物、完整示例文件和 tarball。需要源码、二开包或商业自助开通的用户，可以前往 <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">https://dev.flyfish.group/shop</a>，付费 4.99 后自助开通。</p><h2 id="二开或商用需要注意什么" tabindex="-1">二开或商用需要注意什么 <a class="header-anchor" href="#二开或商用需要注意什么" aria-label="Permalink to &quot;二开或商用需要注意什么&quot;">​</a></h2><p>项目使用 <code>Apache-2.0</code> 许可证。二开或商用时，请保留许可证、版权和来源说明，并注明项目来源为 Flyfish Viewer / <code>@flyfish-group/file-viewer3</code>。如果修复了通用问题或增强了通用能力，建议通过 issue / PR 贡献回来。</p>',44)])])}const u=a(l,[["render",c]]);export{f as __pageData,u as default};
